import (
	"fmt"
	"strings"
)

func solve(n int64) string {
	// Calculate n squared and n cubed
	n2 := n * n
	n3 := n * n * n

	// Convert n2 to hexadecimal
	hexDigits := "0123456789ABCDEF"
	var hexStr strings.Builder
	for n2 > 0 {
		remainder := n2 % 16
		hexStr.WriteRune(hexDigits[remainder])
		n2 /= 16
	}
	// Reverse to get the correct order
	hexStr.String()
	hexStr = hexStr.String()
	for i, j := 0, len(hexStr)-1; i < j; i, j = i+1, j-1 {
		hexStr[i], hexStr[j] = hexStr[j], hexStr[i]
	}
	hexStr = strings.Builder{}
	for _, c := range hexStr {
		hexStr.WriteRune(c)
	}

	// Convert n3 to base 36
	base36Digits := "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ"
	var base36Str strings.Builder
	for n3 > 0 {
		remainder := n3 % 36
		base36Str.WriteRune(base36Digits[remainder])
		n3 /= 36
	}
	// Reverse to get the correct order
	base36Str.String()
	base36Str = base36Str.String()
	for i, j := 0, len(base36Str)-1; i < j; i, j = i+1, j-1 {
		base36Str[i], base36Str[j] = base36Str[j], base36Str[i]
	}
	base36Str = strings.Builder{}
	for _, c := range base36Str {
		base36Str.WriteRune(c)
	}

	// Concatenate the two strings
	return hexStr.String() + base36Str.String()
}
